module freq_div(
    input CLK_in,
    input RST,
    output CLK_50,
    output CLK_10,
    output CLK_1
);
parameter N = 3;
reg [N-1:0] count_100, count_10;
always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        count_50 <= 0;
    end else if (count_50 == 1) begin
        count_50 <= ~count_50;
    end
end
always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        count_10 <= 0;
    end else if (count_10 == 4) begin
        count_10 <= ~count_10;
    end
end
always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        count_100 <= 0;
    end else if (count_100 == 49) begin
        count_100 <= ~count_100;
    end
end
assign CLK_1 = (count_100 == 49) ? ~CLK_1 : CLK_1;
assign CLK_10 = (count_10 == 4) ? ~CLK_10 : CLK_10;
assign CLK_50 = (count_50 == 1) ? ~CLK_50 : CLK_50;
endmodule
